import{_ as t,o as i,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Android SDK Overview","description":"","frontmatter":{"title":"Android SDK Overview","slug":"android-sdk-overview"},"headers":[],"relativePath":"developer-hub/android-sdk-overview.md","filePath":"developer-hub/android-sdk-overview.md"}'),r={name:"developer-hub/android-sdk-overview.md"};function n(s,e,d,l,h,p){return i(),a("div",null,[...e[0]||(e[0]=[o('<h3 id="sdk-stats" tabindex="-1">SDK Stats <a class="header-anchor" href="#sdk-stats" aria-label="Permalink to &quot;SDK Stats&quot;">​</a></h3><p><strong>Open Source Github Repo</strong>: <a href="https://github.com/BranchMetrics/android-branch-deep-linking" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/android-branch-deep-linking</a></p><p><strong>SDK Size</strong>: 187kb</p><p><strong>Speed</strong>: Median 80ms to 250ms</p><p><strong>Minimum OS Version</strong>: API Level 21+</p><h3 id="android-demo-app" tabindex="-1">Android Demo App <a class="header-anchor" href="#android-demo-app" aria-label="Permalink to &quot;Android Demo App&quot;">​</a></h3><p><strong>Want to take our technology for a test drive before implementing it?</strong></p><p><a href="https://play.google.com/store/apps/details?id=io.branch.branchster" target="_blank" rel="noreferrer">DOWNLOAD BRANCH MONSTER FACTORY</a></p><p><strong>Want to dive into the code directly?</strong></p><p><a href="https://github.com/BranchMetrics/Branch-Example-Deep-Linking-Branchster-Android" target="_blank" rel="noreferrer">VIEW BRANCH MONSTER FACTORY GITHUB</a></p><h3 id="basic-integration" tabindex="-1">Basic Integration <a class="header-anchor" href="#basic-integration" aria-label="Permalink to &quot;Basic Integration&quot;">​</a></h3><p><strong>Integrating the Branch Android SDK is required for the following features:</strong></p><ul><li>Ads</li><li>Email</li><li>Journeys</li></ul><p><a href="./android-basic-integration.html">INTEGRATE THE BRANCH SDK</a></p><h3 id="advanced-features" tabindex="-1">Advanced Features <a class="header-anchor" href="#advanced-features" aria-label="Permalink to &quot;Advanced Features&quot;">​</a></h3><p><strong>On top of the basic integration, you can implement the following features:</strong></p><ul><li>Create content reference</li><li>Create deep link</li><li>Share deep link</li><li>Read deep link</li><li>Navigate to content</li><li>Display content</li><li>Track content</li><li>Track users</li><li>Handle push notifications</li><li>Handle links in your own app</li></ul><p><a href="./android-advanced-features.html">IMPLEMENT ADVANCED FEATURES</a></p><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><p><strong>Test your Branch integration before your app goes live.</strong></p><p><a href="./android-testing.html">TEST THE INTEGRATION</a></p><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h3><p><strong>Running into issues? Browse our troubleshooting section to find a solution.</strong></p><p><a href="./android-troubleshooting.html">SEARCH SOLUTIONS</a></p><h3 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h3><p><strong>View past versions of the Branch SDK for Android including changes.</strong></p><p><a href="./android-version-history.html">VIEW VERSION HISTORY</a></p><h3 id="full-reference" tabindex="-1">Full Reference <a class="header-anchor" href="#full-reference" aria-label="Permalink to &quot;Full Reference&quot;">​</a></h3><p><strong>The information presented here serves as a reference manual for our Android SDK.</strong></p><p><a href="./android-full-reference.html">VIEW FULL REFERENCE</a></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Why do we recommend initializing the SDK in onStart() versus onCreate() in Android?</summary><p><code>onCreate()</code> is called when the Activity is first created and not when the activity is backgrounded. The Branch SDK is to be initialized every time the activity is foregrounded. If the activity is backgrounded and then foregrounded, this callback is not guaranteed to be called and hence the SDK will not be initialized.</p><p>The recommended way to initialize the Branch SDK is in <code>onStart()</code>. This is where you need to initialize the SDK since this callback is triggered every time the app is started whether from a cold start or a warm start. This is the callback that makes the activity visible to the user.</p></details><details><summary>Why does my Android app crash when opening from a Branch link?</summary><p>This mostly happens when there is a problem with the AndroidManifest.xml file. Please check to make sure that the entries added for App Links are not broken and are added inside the correct launcher activity.</p><p>Also, ensure that the entry for application name points to an existing Application class.</p></details><details><summary>How do I know if my Android app links are configured properly?</summary><p>You can check on which app links will open the app directly by doing the following:</p><p>Navigate to <strong>App Info</strong> &gt; <strong>Advanced</strong> &gt; <strong>Open by Default</strong> &gt; <strong>Supported Links</strong>. This will show all the app links that are enabled for your app.</p></details><details><summary>Why does my Android app call Branch multiple times when resuming?</summary><p>This behavior is often a consequence of the launchMode parameter in the Android manifest being set incorrectly. Make sure that launchMode in the manifest is set as follows:</p><p><code>android:launchMode=&#39;singleTask&#39;</code></p><p>When this is not set, or is set incorrectly, the activity may fire twice.</p></details><details><summary>Why did Google Play remove my app from the store?</summary><p>In older versions of the Branch Android SDK (1.2.6 to 2.11.0) calls were made to <a href="https://api.branch.io/v1/applist" target="_blank" rel="noreferrer">https://api.branch.io/v1/applist</a> endpoint. We disabled and deprecated this endpoint in 2015, but it seems that it is not enough. We believe a recent update to the Google Play Store policies prompted these new violations. In response, Branch has removed all the potentially hostile code from our Android SDK and released an updated version on 8/14/17. This was limited to our Android SDK and our latest SDK complies with the privacy policies of the Play Store.</p><p>Please update your Android app to use the latest version (v 2.11.1) of the Branch SDK and re-submit it to the Play Store.</p></details><details><summary>How does Charles Proxy relate to my Android app?</summary><p>Since Android N, you are not able to proxy to apps unless it is your own app. What this means is:</p><ol><li>You need to download the .apk.</li><li>Add the code in the <a href="https://developers.google.com/admob/android/charles" target="_blank" rel="noreferrer">instructions</a>​.</li><li>Recompile it.</li></ol></details><details><summary>How do I stop collecting the SSAID (android\\_id)?</summary><p>The SSAID or android_id is a persistent hardware identifier that is “common between apps signed by the same developer signing key.” Branch utilizes this for many use cases such as Fraud and to provide the best user experience across different apps. If you wish for Branch not to collect the SSAID, you can call <code>Branch.disableDeviceIDFetch()</code> within <code>onCreate()</code> of your Application Class.</p><p>When this method is enabled, the SDK will fallback to generating a UUID as a hardware id.</p></details><details><summary>Why does my app not open directly when it gives an option to choose between browser and app?</summary><p>On Android, <strong>if the App Links are enabled correctly, they should never show the dialog box to choose between a browser and the app as mentioned in the</strong> <a href="https://developer.android.com/training/app-links/verify-site-associations" target="_blank" rel="noreferrer"><strong>Android documentation</strong></a><strong>.</strong></p><h3 id="troubleshooting-steps" tabindex="-1">Troubleshooting Steps <a class="header-anchor" href="#troubleshooting-steps" aria-label="Permalink to &quot;Troubleshooting Steps&quot;">​</a></h3><ol><li><p>Confirm the device browser is NOT the default handler for xx.app.link domain.</p><ul><li>Android App Links sets the app as the default handler for a domain (i.e., xx.app.link). If a user clicks a link before App Links is enabled, they’ll have the option to open in browser or in-app. If the browser is selected with “always”, that domain will never open the app.</li><li>Reset browser defaults: Settings → Apps → select the browser → Defaults → “Clear Defaults”.</li></ul></li><li><p>If one domain is failing verification, App Links is disabled for every other domain too.</p><ul><li>Every domain &amp; subdomain in Manifest must host a DAL file at: https://[domain]/.well-known/assetlinks.json</li><li>Even if <code>autoVerify=&quot;true&quot;</code> is not in all intent filters, Android will scrape every domain.</li></ul></li><li><p>Confirm Branch dashboard &amp; all other DAL files contain the correct SHA 256 fingerprint.</p></li><li><p>Confirm app’s compileSdkVersion in build.gradle is 23+.</p></li><li><p>All link domains must be publicly accessible (not behind firewall/vpn) and accessible by Google&#39;s bots.</p></li><li><p>Validate App Links: Install app &gt; connect device to Android Studio &gt; ./adb shell dumpsys package d.</p></li></ol><p><em>[Image: 520]</em></p><p>Successful verification</p><p><em>[Image: 327]</em></p><p>Failed verification</p></details><details><summary>How do I continue accessing GAID after Android 12?</summary><p>Google will <a href="https://support.google.com/googleplay/android-developer/answer/6048248?hl=en" target="_blank" rel="noreferrer">implement some changes to GAID access</a> beginning in April 2022. If your app targets Android 13, you will need to declare new <code>AD_ID</code> permission to continue collecting GAIDs for users on Android 13.</p><p>To ensure your Branch attribution data remains reliable and complete, please take either of the following actions before April 2022:</p><ol><li>Confirm that your Google Mobile Ads SDK (play-services-ads-identifier) SDK is version 17.1.0+ (released September 2021). Versions 17.1.0 and above of this SDK automatically merge the <code>AD_ID</code> permission, allowing your app to continue properly ingesting the GAID.<br><strong>OR</strong></li><li>If you prefer not to update your Google Mobile Ads SDK at this time, you may explicitly declare the new AD_ID permission () in your app&#39;s manifest file. More information on how to do this is available <a href="./android-basic-integration.html">here</a>.</li></ol></details><details><summary>Will the GAID changes impact our attribution on Branch?</summary><p>Since the introduction of zeroed out GAIDs is the same feature as Limit Ad Tracking and Limit Ad Tracking has been available on Android for years, we do not expect a sudden decrease in Attribution or heavily impact our Attribution reporting. This is primarily because Branch <strong>does not</strong> collect the GAID when Limit Ad Tracking is enabled by the end-user.</p><p>With that said, many Ad Networks are implementing alternative parameters and methodologies to provide accurate attribution reporting even with Limit Ad Tracking enabled. Please evaluate the matrix below.</p><h3 id="impact-on-sources-when-gaid-is-zeroed-and-limit-ad-tracking-is-enabled" tabindex="-1">Impact on Sources when GAID is Zeroed and Limit Ad Tracking is Enabled <a class="header-anchor" href="#impact-on-sources-when-gaid-is-zeroed-and-limit-ad-tracking-is-enabled" aria-label="Permalink to &quot;Impact on Sources when GAID is Zeroed and Limit Ad Tracking is Enabled&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>Alternate Param/ID</th><th>Install</th><th>Open</th><th>Downstream Events</th></tr></thead><tbody><tr><td>Facebook</td><td><a href="./facebook-install-referrer.html">Facebook Install Referrer</a></td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Google</td><td>Market Referrer GCLID</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Twitter</td><td>Unknown</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Snap</td><td>Probabilistic Attribution for Android</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Non-SANs</td><td>No changes as Branch Links are used.</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Other Branch Features</td><td><a href="./predictive-modeling.html">PREM</a></td><td>Yes</td><td>Yes</td><td>Yes</td></tr></tbody></table></details><details><summary>Why are Branch Links always taking me to the Google Play Store on Android 12?</summary><p>With the introduction of Android 12, Google has implemented some new updates to how Android App Links function and how they are properly verified. One update we have observed, but are unable to find official Google documentation, is the lack of auto-verification and support for Application ID Suffixes.</p><p>Application ID suffix is something for Android to allow apps to differentiate builds with different app IDs.<br> For example:<br><strong>Production Build:</strong> io.branch<br><strong>QA Build:</strong> io.branch.qa<br><strong>Staging Build:</strong> io.branch.staging</p><p>Please check your {domain}.app.link/.well-known/assetlinks.json or {domain}.test-app.link/.well-known/assetlinks.json (generated by Branch when you select the <strong>Enable App Links</strong> checkbox in Branch) file to ensure the proper packages are declared. We have observed that all packages, including their Application ID Suffixes, need to be explicitly declared on the Digital Asset Links files that Branch hosts on your Branch Links (app.link).</p><p>We strongly recommend utilizing Androids <a href="https://developer.android.com/training/app-links/verify-site-associations" target="_blank" rel="noreferrer">App Link Verification Instructions</a> to identify and confirm the root cause.</p><p>Additionally, Branch has noticed the enforcement of explicitly declaring hosts for your Branch URI Scheme within the intent filter of your manifest. By default Branch will utilize the open host (i.e {uri-scheme}😕/open?....), however, when utilizing deeplink_paths, we can replace the open host with your $deeplink_path. If you do use $deeplink_path, please explicitly declare those paths for your host or utilize a wildcard. <a href="./android-basic-integration.html">Android Basic Integration - Configure App</a></p><p>If you are noticing Branch Links not working on Android 12 devices with your app targeting API 31+, please contact your Branch Account team or <a href="./submit-a-ticket.html">Submit a Ticket</a>.</p></details>',42)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
